const http = require('http');
const { spawn } = require('child_process');

exports.runConversion = function (context, req) {
    const inputFilename = req.body.inputFilename;
    const outputFormat = req.body.outputFormat;

    if (!inputFilename || !outputFormat) {
        context.log.error("Missing required parameters");
        return { status: 400, body: "Missing required parameters" };
    }

    const libreOfficePath = '/path/to/libreoffice';
    const command = `${libreOfficePath} --headless --convert-to ${outputFormat} ${inputFilename}`;

    spawn(command, {
        shell: true,
        env: { PATH: process.env.PATH }
    })
    .on('exit', (code) => {
        if (code === 0) {
            context.log.info(`Conversion successful for file ${inputFilename}`);
            const response = {
                status: 200,
                body: `Conversion successful for file ${inputFilename}`
            };
            context.res = response;
        } else {
            context.log.error(`Error converting file ${inputFilename}: exit code ${code}`);
            const response = {
                status: 500,
                body: `Error converting file ${inputFilename}: exit code ${code}`
            };
            context.res = response;
        }
    })
    .on('error', (err) => {
        context.log.error(`Error running LibreOffice command: ${err}`);
        const response = {
            status: 500,
            body: `Error running LibreOffice command: ${err}`
        };
        context.res = response;
    });
};